import{_ as e,o as r,c as a,a0 as o}from"./chunks/framework.CkNTPv-z.js";const p=JSON.parse('{"title":"ILGA Resources & Rainbow Map","description":"Using ILGA resources to research trans rights worldwide","frontmatter":{"layout":"doc","title":"ILGA Resources & Rainbow Map","description":"Using ILGA resources to research trans rights worldwide"},"headers":[],"relativePath":"europe/ilga-resources.md","filePath":"europe/ilga-resources.md","lastUpdated":null}'),i={name:"europe/ilga-resources.md"};function s(n,t,l,d,c,h){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="🌈-ilga-resources-rainbow-map" tabindex="-1">🌈 ILGA Resources &amp; Rainbow Map <a class="header-anchor" href="#🌈-ilga-resources-rainbow-map" aria-label="Permalink to &quot;🌈 ILGA Resources &amp; Rainbow Map&quot;">​</a></h1><p>ILGA (International Lesbian, Gay, Bisexual, Trans and Intersex Association) provides some of the most comprehensive data on LGBTQ+ rights worldwide. Here&#39;s how to use their resources to research your next destination.</p><h2 id="ilga-europe-—-rainbow-map" tabindex="-1">ILGA Europe — Rainbow Map <a class="header-anchor" href="#ilga-europe-—-rainbow-map" aria-label="Permalink to &quot;ILGA Europe — Rainbow Map&quot;">​</a></h2><p>The <strong>Rainbow Map</strong> ranks 49 European countries on LGBTI equality across 6 categories:</p><ol><li><strong>Equality and non-discrimination</strong></li><li><strong>Family</strong></li><li><strong>Hate crime and hate speech</strong></li><li><strong>Legal gender recognition</strong></li><li><strong>Intersex bodily integrity</strong></li><li><strong>Asylum</strong></li></ol><p><strong>🔗 Access the live map</strong>: <a href="https://www.ilga-europe.org/resources/rainbow-map" target="_blank" rel="noreferrer">ILGA Europe Rainbow Map</a></p><h3 id="top-ranked-countries-latest-report" tabindex="-1">Top-Ranked Countries (Latest Report) <a class="header-anchor" href="#top-ranked-countries-latest-report" aria-label="Permalink to &quot;Top-Ranked Countries (Latest Report)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Rank</th><th>Country</th><th>Score</th></tr></thead><tbody><tr><td>1</td><td>🇲🇹 Malta</td><td>88%</td></tr><tr><td>2</td><td>🇩🇰 Denmark</td><td>77%</td></tr><tr><td>3</td><td>🇧🇪 Belgium</td><td>72%</td></tr><tr><td>4</td><td>🇬🇧 UK</td><td>69%</td></tr><tr><td>5</td><td>🇪🇸 Spain</td><td>68%</td></tr><tr><td>6</td><td>🇫🇷 France</td><td>67%</td></tr><tr><td>7</td><td>🇳🇱 Netherlands</td><td>66%</td></tr><tr><td>8</td><td>🇮🇸 Iceland</td><td>65%</td></tr><tr><td>9</td><td>🇩🇪 Germany</td><td>63%</td></tr><tr><td>10</td><td>🇫🇮 Finland</td><td>61%</td></tr></tbody></table><blockquote><p><strong>Note</strong>: Scores are based on legal and policy criteria, not social acceptance or healthcare access. Use this alongside our Country Guides for a complete picture.</p></blockquote><h2 id="ilga-world-—-state-sponsored-homophobia-report" tabindex="-1">ILGA World — State-Sponsored Homophobia Report <a class="header-anchor" href="#ilga-world-—-state-sponsored-homophobia-report" aria-label="Permalink to &quot;ILGA World — State-Sponsored Homophobia Report&quot;">​</a></h2><p>The <strong>State-Sponsored Homophobia</strong> report maps sexual orientation laws globally:</p><ul><li><strong>🔗 <a href="https://ilga.org/maps-sexual-orientation-laws" target="_blank" rel="noreferrer">ILGA World Maps</a></strong></li><li>Tracks criminalization, protections, and recognition laws</li><li>Updated annually</li></ul><h3 id="key-trans-specific-resources-from-ilga" tabindex="-1">Key Trans-Specific Resources from ILGA <a class="header-anchor" href="#key-trans-specific-resources-from-ilga" aria-label="Permalink to &quot;Key Trans-Specific Resources from ILGA&quot;">​</a></h3><ol><li><p><strong>Trans Legal Mapping Report</strong></p><ul><li>Comprehensive global survey of trans-specific laws</li><li>Covers legal gender recognition, name changes, healthcare access</li><li>🔗 <a href="https://ilga.org/trans-report" target="_blank" rel="noreferrer">ILGA Trans Report</a></li></ul></li><li><p><strong>Trans Murder Monitoring</strong></p><ul><li>Global data on reported murders of trans people</li><li>🔗 <a href="https://transrespect.org/en/trans-murder-monitoring/" target="_blank" rel="noreferrer">TGEU Trans Murder Monitoring</a></li></ul></li><li><p><strong>Global Regulations Database</strong></p><ul><li>Searchable database of LGBTQ+ laws by country</li><li>🔗 <a href="https://database.ilga.org/" target="_blank" rel="noreferrer">ILGA Database</a></li></ul></li></ol><h2 id="how-to-use-ilga-data-for-relocation-research" tabindex="-1">How to Use ILGA Data for Relocation Research <a class="header-anchor" href="#how-to-use-ilga-data-for-relocation-research" aria-label="Permalink to &quot;How to Use ILGA Data for Relocation Research&quot;">​</a></h2><h3 id="step-1-check-the-rainbow-map" tabindex="-1">Step 1: Check the Rainbow Map <a class="header-anchor" href="#step-1-check-the-rainbow-map" aria-label="Permalink to &quot;Step 1: Check the Rainbow Map&quot;">​</a></h3><ul><li>Go to the <a href="https://www.ilga-europe.org/resources/rainbow-map" target="_blank" rel="noreferrer">Rainbow Map</a></li><li>Click on any country to see detailed scores</li><li>Focus on <strong>Legal Gender Recognition</strong> and <strong>Hate Crime</strong> categories</li></ul><h3 id="step-2-read-the-country-report" tabindex="-1">Step 2: Read the Country Report <a class="header-anchor" href="#step-2-read-the-country-report" aria-label="Permalink to &quot;Step 2: Read the Country Report&quot;">​</a></h3><ul><li>Each country has a full legal report</li><li>Look for: <ul><li>✓ Self-ID laws</li><li>✓ Informed consent healthcare</li><li>✓ Anti-discrimination protections</li><li>✓ Hate crime laws</li></ul></li></ul><h3 id="step-3-cross-reference-with-our-guides" tabindex="-1">Step 3: Cross-Reference with Our Guides <a class="header-anchor" href="#step-3-cross-reference-with-our-guides" aria-label="Permalink to &quot;Step 3: Cross-Reference with Our Guides&quot;">​</a></h3><ul><li>Use our <strong><a href="/transit/europe/">Country Guides</a></strong> for practical information on: <ul><li>Healthcare access and clinics</li><li>Immigration pathways</li><li>Community resources</li><li>Cost of living</li></ul></li></ul><h3 id="step-4-verify-current-information" tabindex="-1">Step 4: Verify Current Information <a class="header-anchor" href="#step-4-verify-current-information" aria-label="Permalink to &quot;Step 4: Verify Current Information&quot;">​</a></h3><ul><li>Laws change frequently — always verify with official sources</li><li>Contact local LGBTQ+ organizations for current conditions</li><li>Join expat LGBTQ+ forums for firsthand experiences</li></ul><h2 id="limitations-of-ilga-data" tabindex="-1">Limitations of ILGA Data <a class="header-anchor" href="#limitations-of-ilga-data" aria-label="Permalink to &quot;Limitations of ILGA Data&quot;">​</a></h2><p>While ILGA provides excellent legal analysis, it doesn&#39;t cover:</p><ul><li><strong>Healthcare quality</strong> and wait times</li><li><strong>Social acceptance</strong> in different regions</li><li><strong>Cost of living</strong> and economic factors</li><li><strong>Practical immigration processes</strong></li><li><strong>Community resources</strong> and support networks</li></ul><p>Use our <strong>Country Guides</strong> and <strong>Global Index</strong> alongside ILGA data for comprehensive research.</p><h2 id="other-useful-resources" tabindex="-1">Other Useful Resources <a class="header-anchor" href="#other-useful-resources" aria-label="Permalink to &quot;Other Useful Resources&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Organization</th><th>Focus</th><th>Link</th></tr></thead><tbody><tr><td><strong>Transgender Europe (TGEU)</strong></td><td>Trans-specific rights in Europe</td><td><a href="https://tgeu.org/" target="_blank" rel="noreferrer">tgeu.org</a></td></tr><tr><td><strong>Human Rights Watch</strong></td><td>General human rights reports</td><td><a href="https://www.hrw.org/" target="_blank" rel="noreferrer">hrw.org</a></td></tr><tr><td><strong>Amnesty International</strong></td><td>LGBTQ+ rights advocacy</td><td><a href="https://www.amnesty.org/" target="_blank" rel="noreferrer">amnesty.org</a></td></tr><tr><td><strong>Equaldex</strong></td><td>Crowdsourced LGBTQ+ rights database</td><td><a href="https://www.equaldex.com/" target="_blank" rel="noreferrer">equaldex.com</a></td></tr><tr><td><strong>Nomad List</strong></td><td>LGBTQ+ friendliness scores + cost data</td><td><a href="https://nomadlist.com/" target="_blank" rel="noreferrer">nomadlist.com</a></td></tr></tbody></table>',29)])])}const g=e(i,[["render",s]]);export{p as __pageData,g as default};
